    10→@Injectable()
    11→export class MarkdownService {
    12→
    13→    constructor(
    14→        private readonly auditingService: AuditingService,
    15→    ) { }
    16→
    17→    async parse(markdown: string | Buffer, encoding: BufferEncoding = 'utf8'): Promise<ExtractedDocument> {
    18→
    19→        const milestoneId = await this.auditingService.createMilestone(
    20→        'markdown-parse',
    21→            { 
    22→                methodName: 'parse',
    23→                className: 'MarkdownService'
    24→            }
    25→        );
    26→
    27→        try {
    28→            const ast = await this.parseMarkdownToAst(markdown, encoding);
    29→            const paras = await this.parseAst(ast);
    30→            const text = paras.map(p => p.text).join("\n");
    31→
    32→            await this.auditingService.complete(milestoneId, {
    33→                success: true,
    34→                nodesCreated: paras.length
    35→            });
    36→
    37→            return {
    38→                id: generateGuid(text),
    39→                paragraphs: paras
    40→            };
    41→            
    42→        } catch (error) {
    43→            await this.auditingService.fail(milestoneId, error);
    44→            throw error;
    45→        }
    46→    }
    47→    /**
    48→     * Parse markdown (string or buffer) into a remark AST
    49→     * @param markdown - The markdown string or buffer to parse
    50→     * @param encoding - Buffer encoding (default: 'utf8')
    51→     * @returns Promise<Root> - The parsed AST
    52→     */
    53→    async parseMarkdownToAst(
    54→        markdown: string | Buffer,
    55→        encoding: BufferEncoding = 'utf8'
    56→    ): Promise<Root> {
    57→        const processor = unified()
    58→            .use(remarkParse);
    59→
    60→        const content = Buffer.isBuffer(markdown) ? markdown.toString(encoding) : markdown;
    61→        const ast = processor.parse(content);
    62→        return ast;
    63→    }
    64→
    65→    parseAst(ast): any {
    66→        const parser = new AstParser();
    67→        const data = parser.extractParagraphs(ast);
    68→        return data;
    69→    }
    70→
    71→}
