     7→@Injectable()
     8→export class AuditingService {
     9→  private readonly logger = new Logger(AuditingService.name);
    10→
    11→  constructor(
    12→    private readonly loggingStorage: LoggingStorage,
    13→    private readonly auditRepository: AuditingRepository,
    14→  ) {}
    15→
    16→  /**
    17→   * Create REQUEST audit (controller level)
    18→   */
    19→  async createRequestAudit(category: string): Promise<string> {
    20→    const cls_id = this.loggingStorage.getTraceId();
    21→    this.logger.debug(
    22→      `[AUDIT] Creating REQUEST audit: cls_id=${cls_id}, category=${category}`,
    23→    );
    24→
    25→    try {
    26→      const audit = await this.auditRepository.createAudit({
    27→        cls_id,
    28→        category,
    29→      });
    30→      return audit.id;
    31→    } catch (error) {
    32→      this.logger.error(
    33→        `Failed to create REQUEST audit: ${error.message}`,
    34→        error.stack,
    35→      );
    36→      // Don't re-throw - audit failure shouldn't break the request
    37→      return '';
    38→    }
    39→  }
    40→
    41→  /**
    42→   * Create MILESTONE audit (service level)
    43→   */
    44→  async createMilestone(
    45→    category: string,
    46→    metadata?: Record<string, any>,
    47→  ): Promise<string> {
    48→    const cls_id = this.loggingStorage.getTraceId();
    49→    this.logger.debug(
    50→      `[AUDIT] Creating MILESTONE: cls_id=${cls_id}, category=${category}`,
    51→    );
    52→
    53→    try {
    54→      const milestone = await this.auditRepository.createMilestone({
    55→        cls_id,
    56→        category,
    57→        metadata,
    58→      });
    59→      return milestone.id;
    60→    } catch (error) {
    61→      this.logger.error(
    62→        `Failed to create MILESTONE: ${error.message}`,
    63→        error.stack,
    64→      );
    65→      return '';
    66→    }
    67→  }
    68→
    69→  /**
    70→   * Complete an audit/milestone
    71→   */
    72→  async complete(id: string, metadata?: Record<string, any>): Promise<void> {
    73→    if (!id) return; // Guard against empty IDs
    74→
    75→    try {
    76→      await this.auditRepository.updateStatus(id, AuditStatus.COMPLETED, metadata);
    77→    } catch (error) {
    78→      this.logger.error(
    79→        `Failed to complete audit ${id}: ${error.message}`,
    80→        error.stack,
    81→      );
    82→      // Don't re-throw - audit failure shouldn't break the request
    83→    }
    84→  }
    85→
    86→  /**
    87→   * Fail an audit/milestone
    88→   */
    89→  async fail(
    90→    id: string,
    91→    error: Error,
    92→    metadata?: Record<string, any>,
    93→  ): Promise<void> {
    94→    if (!id) return; // Guard against empty IDs
    95→
    96→    try {
    97→      await this.auditRepository.markFailed(id, error, metadata);
    98→    } catch (dbError) {
    99→      this.logger.error(
   100→        `Failed to mark audit ${id} as failed: ${dbError.message}`,
   101→        dbError.stack,
   102→      );
   103→      // Don't re-throw - audit failure shouldn't break the request
   104→    }
   105→  }
   106→
   107→  /**
   108→   * Get full trace (all audits/milestones for a cls_id)
   109→   */
   110→  async getFullTrace(
   111→    cls_id?: string,
   112→  ): Promise<{
   113→    request: any;
   114→    milestones: any[];
   115→  }> {
   116→    const trace_id = cls_id || this.loggingStorage.getTraceId();
   117→    const audits = await this.auditRepository.findByClsId(trace_id);
   118→
   119→    return {
   120→      request: audits.find((a) => a.operation_type === OperationType.REQUEST),
   121→      milestones: audits.filter((a) => a.operation_type === OperationType.MILESTONE),
   122→    };
   123→  }
   124→
   125→  /**
   126→   * Get statistics
   127→   */
   128→  async getStats(category?: string, operationType?: OperationType) {
   129→    return this.auditRepository.getStats(category, operationType);
   130→  }
   131→
   132→}
