     2→import { Injectable, Logger } from '@nestjs/common';
     3→import { DataSource, Repository } from 'typeorm';
     4→import { AuditEntity, AuditStatus, OperationType } from './audit.entity';
     5→
     6→@Injectable()
     7→export class AuditingRepository extends Repository<AuditEntity> {
     8→  private readonly logger = new Logger(AuditingRepository.name);
     9→
    10→  constructor(private readonly dataSource: DataSource) {
    11→    super(AuditEntity, dataSource.createEntityManager());
    12→  }
    13→
    14→  /**
    15→   * Create an audit record (REQUEST level)
    16→   */
    17→  async createAudit(data: {
    18→    cls_id: string;
    19→    category: string;
    20→  }): Promise<AuditEntity> {
    21→    const audit = this.create({
    22→      cls_id: data.cls_id,
    23→      operation_type: OperationType.REQUEST,
    24→      category: data.category,
    25→      status: AuditStatus.STARTED,
    26→      started: new Date(),
    27→    });
    28→    return await this.save(audit);
    29→  }
    30→
    31→  /**
    32→   * Create a milestone record (MILESTONE level)
    33→   */
    34→  async createMilestone(data: {
    35→    cls_id: string;
    36→    category: string;
    37→    metadata?: Record<string, any>;
    38→  }): Promise<AuditEntity> {
    39→    const milestone = this.create({
    40→      cls_id: data.cls_id,
    41→      operation_type: OperationType.MILESTONE,
    42→      category: data.category,
    43→      status: AuditStatus.STARTED,
    44→      started: new Date(),
    45→      metadata: data.metadata || {},
    46→    });
    47→    return await this.save(milestone);
    48→  }
    49→
    50→  /**
    51→   * Find all audits/milestones for a specific trace
    52→   */
    53→  async findByClsId(cls_id: string): Promise<AuditEntity[]> {
    54→      return await this.find({
    55→      where: { cls_id },
    56→      order: { started: 'ASC' },
    57→    });
    58→  }
    59→
    60→  /**
    61→   * Find REQUEST level audits for a trace
    62→   */
    63→  async findRequestsByClsId(cls_id: string): Promise<AuditEntity[]> {
    64→    return await this.find({
    65→      where: {
    66→        cls_id,
    67→        operation_type: OperationType.REQUEST,
    68→      },
    69→      order: { started: 'ASC' },
    70→    });
    71→  }
    72→
    73→  /**
    74→   * Find MILESTONE level records for a trace
    75→   */
    76→  async findMilestonesByClsId(cls_id: string): Promise<AuditEntity[]> {
    77→    return await this.find({
    78→      where: {
    79→        cls_id,
    80→        operation_type: OperationType.MILESTONE,
    81→      },
    82→      order: { started: 'ASC' },
    83→    });
    84→  }
    85→
    86→  /**
    87→   * Update audit status and metadata
    88→   */
    89→  async updateStatus(
    90→    id: string,
    91→    status: AuditStatus,
    92→    metadata?: Record<string, any>,
    93→  ): Promise<AuditEntity | null> {
    94→    const audit = await this.findOne({ where: { id } });
    95→    if (!audit) return null;
    96→
    97→    audit.status = status;
    98→    if (metadata) {
    99→      audit.metadata = { ...audit.metadata, ...metadata };
   100→    }
   101→
   102→    // Set timestamps based on status
   103→    if (status === AuditStatus.STARTED && !audit.started) {
   104→      audit.started = new Date();
   105→    }
   106→    if (
   107→      [AuditStatus.COMPLETED, AuditStatus.FAILED].includes(status) &&
   108→      !audit.completed
   109→    ) {
   110→      audit.completed = new Date();
   111→      if (audit.started) {
   112→        audit.duration = audit.completed.getTime() - audit.started.getTime();
   113→      }
   114→    }
   115→
   116→    return await this.save(audit);
   117→  }
   118→
   119→  /**
   120→   * Mark as failed with error
   121→   */
   122→  async markFailed(
   123→    id: string,
   124→    error: Error,
   125→    metadata?: Record<string, any>,
   126→  ): Promise<AuditEntity | null> {
   127→    const audit = await this.findOne({ where: { id } });
   128→    if (!audit) return null;
   129→
   130→    audit.status = AuditStatus.FAILED;
   131→    audit.error = error.message.substring(0, 2000);
   132→    audit.completed = new Date();
   133→    if (audit.started) {
   134→      audit.duration = audit.completed.getTime() - audit.started.getTime();
   135→    }
   136→
   137→    if (metadata) {
   138→      audit.metadata = { ...audit.metadata, ...metadata };
   139→    }
   140→
   141→    return await this.save(audit);
   142→  }
   143→
   144→  /**
   145→   * Get all failed audits
   146→   */
   147→  async getFailedAudits(
   148→    limit: number = 50,
   149→    operationType?: OperationType,
   150→  ): Promise<AuditEntity[]> {
   151→    const query = this.createQueryBuilder('audit').where(
   152→      'audit.status = :status',
   153→      { status: AuditStatus.FAILED },
   154→    );
   155→
   156→    if (operationType) {
   157→      query.andWhere('audit.operation_type = :operationType', { operationType });
   158→    }
   159→
   160→    return await query.orderBy('audit.started', 'DESC').take(limit).getMany();
   161→  }
   162→
   163→  /**
   164→   * Get in-progress audits
   165→   */
   166→  async getInProgressAudits(
   167→    operationType?: OperationType,
   168→  ): Promise<AuditEntity[]> {
   169→    const query = this.createQueryBuilder('audit').where(
   170→      'audit.status IN (:...statuses)',
   171→      {
   172→        statuses: [AuditStatus.CREATED, AuditStatus.STARTED, AuditStatus.PROCESSING],
   173→      },
   174→    );
   175→
   176→    if (operationType) {
   177→      query.andWhere('audit.operation_type = :operationType', { operationType });
   178→    }
   179→
   180→    return await query.orderBy('audit.started', 'DESC').getMany();
   181→  }
   182→
   183→  /**
   184→   * Get statistics grouped by category and operation type
   185→   */
   186→  async getStats(
   187→    category?: string,
   188→    operationType?: OperationType,
   189→  ): Promise<{
   190→    totalCount: number;
   191→    createdCount: number;
   192→    processingCount: number;
   193→    completedCount: number;
   194→    failedCount: number;
   195→    averageDuration: number;
   196→  }> {
   197→    let query = this.createQueryBuilder('audit');
   198→
   199→    if (category) {
   200→      query.where('audit.category = :category', { category });
   201→    }
   202→    if (operationType) {
   203→      query.andWhere('audit.operation_type = :operationType', { operationType });
   204→    }
   205→
   206→    const stats = await query
   207→      .select('COUNT(*)', 'total')
   208→      .addSelect(
   209→        'COUNT(CASE WHEN audit.status = :created THEN 1 END)',
   210→        'created',
   211→      )
   212→      .addSelect(
   213→        'COUNT(CASE WHEN audit.status IN (:...processing) THEN 1 END)',
   214→        'processing',
   215→      )
   216→      .addSelect(
   217→        'COUNT(CASE WHEN audit.status = :completed THEN 1 END)',
   218→        'completed',
   219→      )
   220→      .addSelect(
   221→        'COUNT(CASE WHEN audit.status = :failed THEN 1 END)',
   222→        'failed',
   223→      )
   224→      .addSelect('AVG(CAST(audit.duration AS INTEGER))', 'avgDuration')
   225→      .setParameters({
   226→        created: AuditStatus.CREATED,
   227→        processing: [AuditStatus.STARTED, AuditStatus.PROCESSING],
   228→        completed: AuditStatus.COMPLETED,
   229→        failed: AuditStatus.FAILED,
   230→      })
   231→      .getRawOne();
   232→
   233→    return {
   234→      totalCount: parseInt(stats.total, 10) || 0,
   235→      createdCount: parseInt(stats.created, 10) || 0,
   236→      processingCount: parseInt(stats.processing, 10) || 0,
   237→      completedCount: parseInt(stats.completed, 10) || 0,
   238→      failedCount: parseInt(stats.failed, 10) || 0,
   239→      averageDuration: Math.round(parseFloat(stats.avgDuration) || 0),
   240→    };
   241→}
   242→
   243→  /**
   244→   * Cleanup old records.
   245→   * @throws Error if days is less than 1 — a zero or negative value would produce a future
   246→   * cutoff date and delete all completed/failed records regardless of age.
   247→   */
   248→  async deleteOlderThan(days: number): Promise<number> {
   249→    if (days < 1) {
   250→      throw new Error(`deleteOlderThan requires days >= 1, got ${days}`);
   251→    }
   252→
   253→    const cutoffDate = new Date();
   254→    cutoffDate.setDate(cutoffDate.getDate() - days);
   255→
   256→    const result = await this.createQueryBuilder('audit')
   257→      .delete()
   258→      .where('audit.status IN (:...statuses)', {
   259→        statuses: [AuditStatus.COMPLETED, AuditStatus.FAILED],
   260→      })
   261→      .andWhere(
   262→        '(audit.started < :cutoffDate OR audit.started IS NULL)',
   263→        { cutoffDate },
   264→      )
   265→      .execute();
   266→
   267→    const count = result.affected || 0;
   268→    this.logger.log(`Deleted ${count} audit records older than ${days} days`);
   269→    return count;
   270→  }
   271→}
